#include<bits/stdc++.h>
using namespace std;
struct segment_tree
{
    struct node
    {
        long long l,r;
        long long lson,rson;
        long long sum,lmax,rmax,ans;
    }t[300010];
    long long cnt;
    segment_tree():cnt(0){}
    void pushup(long long x)
    {
        long long ls=t[x].lson,rs=t[x].rson;
        t[x].sum=t[ls].sum+t[rs].sum;
        t[x].lmax=max(t[ls].lmax,t[ls].sum+t[rs].lmax);
        t[x].rmax=max(t[rs].rmax,t[rs].sum+t[ls].rmax);
        t[x].ans=max({t[ls].ans,t[rs].ans,t[ls].rmax+t[rs].lmax});
    }
    void pushup(node &x,node ls,node rs)
    {
        x.sum=ls.sum+rs.sum;
        x.lmax=max(ls.lmax,ls.sum+rs.lmax);
        x.rmax=max(rs.rmax,rs.sum+ls.rmax);
        x.ans=max({ls.ans,rs.ans,ls.rmax+rs.lmax});
    }
    long long init(long long l,long long r)
    {
        long long x=++cnt;
        t[x].l=l;
        t[x].r=r;
        if(l==r)
        {
            t[x].sum=t[x].lmax=t[x].rmax=t[x].ans=0;
            return x;
        }
        long long mid=(l+r)>>1;
        t[x].lson=init(l,mid);
        t[x].rson=init(mid+1,r);
        pushup(x);
        return x;
    }
    void add(long long x,long long p,long long v)
    {
        if(t[x].l>p||t[x].r<p)
        {
            return;
        }
        if(t[x].l==t[x].r)
        {
            t[x].sum=t[x].lmax=t[x].rmax=t[x].ans+=v;
            return;
        }
        add(t[x].lson,p,v);
        add(t[x].rson,p,v);
        pushup(x);
    }
    node query(long long x,long long l,long long r)
    {
        if(l<=t[x].l&&t[x].r<=r)
        {
            return t[x];
        }
        long long mid=(t[x].l+t[x].r)>>1;
        if(l<=mid&&r>mid)
        {
            node ans=t[x];
            pushup(ans,query(t[x].lson,l,r),query(t[x].rson,l,r));
            return ans;
        }
        else if(l<=mid)
        {
            return query(t[x].lson,l,r);
        }
        else
        {
            return query(t[x].rson,l,r);
        }
    }
}t;
struct query
{
	long long k,l,r,id;
}a[100010];
long long ans[100010];
vector<query> vec[100010];
vector<pair<long long,long long>> v[100010];
int main()
{
	long long n,m;
	scanf("%lld%lld",&n,&m);
	for(long long i=1;i<=m;i++)
	{
		long long l,r,x;
		scanf("%lld%lld%lld",&l,&r,&x);
		v[l].push_back({i,x});
		v[r+1].push_back({i,-x});
	}
	long long q;
	scanf("%lld",&q);
	for(long long i=1;i<=q;i++)
	{
		scanf("%lld%lld%lld",&a[i].k,&a[i].l,&a[i].r);
		a[i].id=i;
		vec[a[i].k].push_back(a[i]);
	}
	t.init(1,m);
	for(long long i=1;i<=n;i++)
	{
		for(auto j:v[i])
		{
			t.add(1,j.first,j.second);
		}
		for(auto j:vec[i])
		{
			ans[j.id]=t.query(1,j.l,j.r).ans;;
		}
	}
	for(long long i=1;i<=q;i++)
	{
		printf("%lld\n",ans[i]);
	}
	return 0;
}
